def test_basic_chain():
    result = topo_sort(3, [[0, 1], [1, 2]])
    assert result == [0, 1, 2]

def test_two_disconnected():
    result = topo_sort(4, [[0, 1], [2, 3]])
    # Any valid topo order is OK; we verify the constraint holds.
    assert result.index(0) < result.index(1)
    assert result.index(2) < result.index(3)
    assert sorted(result) == [0, 1, 2, 3]

def test_cycle():
    assert topo_sort(2, [[0, 1], [1, 0]]) == []

def test_self_loop():
    assert topo_sort(3, [[0, 0]]) == []

def test_no_edges():
    result = topo_sort(3, [])
    assert sorted(result) == [0, 1, 2]

def test_cycle_in_larger_graph():
    assert topo_sort(4, [[0, 1], [1, 2], [2, 3], [3, 1]]) == []

def test_diamond():
    result = topo_sort(4, [[0, 1], [0, 2], [1, 3], [2, 3]])
    assert result.index(0) == 0
    assert result.index(3) == 3
    assert set(result[1:3]) == {1, 2}
